assignee_pat = re.compile(r"owned by (.*?) and has|assigned to (.*?) and has|holds the .*? patent filing .*?, with pub\.|UNIV CALIFORNIA holds", re.IGNORECASE)

def get_assignee(patents_info: str):
    s = patents_info
    # common patterns
    m = re.search(r"owned by ([^,\.]+?) and has", s, flags=re.IGNORECASE)
    if m: return m.group(1).strip()
    m = re.search(r"assigned to ([^,\.]+?) and has", s, flags=re.IGNORECASE)
    if m: return m.group(1).strip()
    m = re.search(r"holds the .*? patent filing .*? is owned by ([^,\.]+?)\b", s, flags=re.IGNORECASE)
    if m: return m.group(1).strip()
    m = re.search(r"^([^\n]+?) holds the", s, flags=re.IGNORECASE)
    if m: return m.group(1).strip()
    return None

