            code = e['code'].replace(' ', '')
            # normalize to subclass group (keep like F25B21/00 already a subgroup; but asked primary CPC subclasses.
            # CPC subclass is first 4 chars + letter? Actually subgroup is like F25B21/00; subclass is F25B.
            # We'll map using available definitions: try exact code, else take first 4.
            primary_codes.append(code)
    if not primary_codes:
        continue
    # map to titles: prefer exact; else try trim to 4-char subclass (e.g., F25B)
    titles=set()
    for code in primary_codes:
        title = cpc_title.get(code)
        if title is None:
            title = cpc_title.get(code.split('/')[0])
        if title is None and len(code)>=4:
            title = cpc_title.get(code[:4])
        if title:
            titles.add(title)
    for t in sorted(titles):
        pairs.append({'citing_assignee': citing_assignee, 'cpc_subclass_title': t})

